import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import styles from "./SavedJobsPage.module.css";
import dashboardStyles from "./DashboardPage.module.css";
import { MainLayout } from "../../layouts";
import { useLanguage } from "../../translet/LanguageContext";
import { useAuth } from "../../contexts/AuthContext";
import { ROUTES } from "../../constants";

export default function SavedJobsPage() {
  const { language } = useLanguage();
  const navigate = useNavigate();
  const { isAuthenticated, loading: authLoading } = useAuth();

  // State
  const [savedJobs, setSavedJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [unsavingJobId, setUnsavingJobId] = useState(null);

  // Modal state
  const [selectedJob, setSelectedJob] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Pagination
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalJobs, setTotalJobs] = useState(0);
  const limit = 9; // 3x3 grid

  // Notification
  const [notification, setNotification] = useState({
    show: false,
    message: "",
    type: "success",
  });

  // Redirect to login if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      navigate(ROUTES.LOGIN);
    }
  }, [isAuthenticated, authLoading, navigate]);

  // Fetch saved jobs
  useEffect(() => {
    if (isAuthenticated) {
      fetchSavedJobs();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page, isAuthenticated]);

  async function fetchSavedJobs() {
    try {
      setLoading(true);
      setError(null);

      const token = localStorage.getItem("authToken");
      const params = new URLSearchParams({
        page: page.toString(),
        limit: limit.toString(),
      });

      const response = await fetch(`/api/jobs/saved/list?${params.toString()}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      if (data.success) {
        setSavedJobs(data.data.savedJobs || []);
        setTotalPages(data.data.pagination?.totalPages || 1);
        setTotalJobs(data.data.pagination?.total || 0);
      }
    } catch (err) {
      console.error("Error fetching saved jobs:", err);
      setError(err.message);
      showNotification("Error loading saved jobs", "error");
    } finally {
      setLoading(false);
    }
  }

  async function handleUnsaveJob(jobId, event) {
    if (event) {
      event.stopPropagation();
    }

    if (unsavingJobId === jobId) return;

    try {
      setUnsavingJobId(jobId);

      const token = localStorage.getItem("authToken");
      const response = await fetch(`/api/jobs/${jobId}/save`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
      });

      const data = await response.json();

      if (data.success && !data.isSaved) {
        // Remove from list
        setSavedJobs((prev) => prev.filter((sj) => sj.jobId !== jobId));
        setTotalJobs((prev) => prev - 1);
        showNotification("Job removed from saved list", "success");
        
        // Close modal if open
        if (isModalOpen && selectedJob?.id === jobId) {
          closeModal();
        }
      } else {
        showNotification(data.message || "Failed to unsave job", "error");
      }
    } catch (error) {
      console.error("Error unsaving job:", error);
      showNotification("An error occurred", "error");
    } finally {
      setUnsavingJobId(null);
    }
  }

  function showNotification(message, type = "success") {
    setNotification({ show: true, message, type });
    setTimeout(() => {
      setNotification((prev) => ({ ...prev, show: false }));
    }, 3000);
  }

  function openModal(job) {
    setSelectedJob(job);
    setIsModalOpen(true);
  }

  function closeModal() {
    setIsModalOpen(false);
    setTimeout(() => setSelectedJob(null), 300);
  }

  function formatDate(dateString) {
    const date = new Date(dateString);
    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  }

  function formatSalary(job) {
    if (job.salaryType === "NEGOTIABLE") return "Negotiable";
    if (job.minSalary && job.maxSalary) {
      return `$${job.minSalary} - $${job.maxSalary}`;
    }
    if (job.minSalary) return `From $${job.minSalary}`;
    return "Contact for details";
  }

  function getWorkingModeDisplay(job) {
    if (!job.workingMode) return "";
    return language === "vi" && job.workingMode.nameVi
      ? job.workingMode.nameVi
      : job.workingMode.name;
  }

  function getDomainsDisplay(job) {
    if (!job.domains || job.domains.length === 0) return [];
    return job.domains.map((d) =>
      language === "vi" && d.nameVi ? d.nameVi : d.name
    );
  }

  if (authLoading || !isAuthenticated) {
    return (
      <MainLayout>
        <div className={styles.loading}>Loading...</div>
      </MainLayout>
    );
  }

  return (
    <MainLayout>
      {/* Notification */}
      {notification.show && (
        <div className={`${styles.notification} ${styles[notification.type]}`}>
          {notification.message}
        </div>
      )}

      <div className={dashboardStyles.dashboardRoot}>
        {/* Sidebar */}
        <aside className={dashboardStyles.sidebar}>
          <div className={dashboardStyles.sidebarHeader}>
            <h2 className={dashboardStyles.sidebarTitle}>Dashboard</h2>
          </div>
          <nav className={dashboardStyles.sidebarNav}>
            <button
              className={dashboardStyles.menuItem}
              onClick={() => navigate(ROUTES.DASHBOARD)}
            >
              <span className={dashboardStyles.menuIcon}>📊</span>
              <span className={dashboardStyles.menuLabel}>Overview</span>
            </button>
            <button
              className={dashboardStyles.menuItem}
              onClick={() => navigate(ROUTES.MY_APPLICATIONS)}
            >
              <span className={dashboardStyles.menuIcon}>📋</span>
              <span className={dashboardStyles.menuLabel}>Applications</span>
            </button>
            <button
              className={`${dashboardStyles.menuItem} ${dashboardStyles.menuItemActive}`}
            >
              <span className={dashboardStyles.menuIcon}>❤️</span>
              <span className={dashboardStyles.menuLabel}>Saved Jobs</span>
            </button>
            <button
              className={dashboardStyles.menuItem}
              onClick={() => navigate(ROUTES.JOB_ALERTS)}
            >
              <span className={dashboardStyles.menuIcon}>🔔</span>
              <span className={dashboardStyles.menuLabel}>Alerts</span>
            </button>
            <button
              className={dashboardStyles.menuItem}
              onClick={() => navigate(ROUTES.PROFILE)}
            >
              <span className={dashboardStyles.menuIcon}>👤</span>
              <span className={dashboardStyles.menuLabel}>Profile</span>
            </button>
          </nav>
        </aside>

        {/* Main Content */}
        <main className={dashboardStyles.mainContent}>
          {/* Header */}
          <header className={dashboardStyles.contentHeader}>
            <h1 className={dashboardStyles.greeting}>❤️ Saved Jobs</h1>
            <p className={dashboardStyles.subGreeting}>
              {totalJobs} {totalJobs === 1 ? "job" : "jobs"} saved for later
            </p>
          </header>

          {/* Content */}
          <div className={styles.contentArea}>
            {/* Loading */}
            {loading && <div className={styles.loading}>Loading saved jobs...</div>}

            {/* Error */}
            {error && <div className={styles.error}>{error}</div>}

            {/* Empty State */}
            {!loading && !error && savedJobs.length === 0 && (
              <div className={styles.emptyState}>
                <div className={styles.emptyIcon}>💼</div>
                <h2 className={styles.emptyTitle}>No saved jobs yet</h2>
                <p className={styles.emptyText}>
                  Start saving jobs you're interested in to view them here
                </p>
                <button className={styles.browseBtn} onClick={() => navigate(ROUTES.FIND_JOB)}>
                  Browse Jobs
                </button>
              </div>
            )}

            {/* Jobs Grid */}
            {!loading && !error && savedJobs.length > 0 && (
              <>
                <div className={styles.jobsGrid}>
                  {savedJobs.map((savedJob) => {
                    const job = savedJob.job;
                    return (
                      <div key={savedJob.id} className={styles.jobCard}>
                        <div className={styles.cardHeader}>
                          <div className={styles.logo}>
                            {job.organization?.logo ? (
                              <img src={job.organization.logo} alt={job.organization.name} />
                            ) : (
                              <span>{job.organization?.name?.[0] || "?"}</span>
                            )}
                          </div>
                          <div className={styles.savedBadge}>
                            ❤️ Saved {formatDate(savedJob.savedDate)}
                          </div>
                        </div>

                        <div className={styles.cardBody}>
                          <h3 className={styles.jobTitle}>{job.title}</h3>
                          <p className={styles.company}>{job.organization?.name}</p>
                          
                          <div className={styles.meta}>
                            <span>📍 {job.province}</span>
                            <span>💼 {getWorkingModeDisplay(job)}</span>
                            <span>💰 {formatSalary(job)}</span>
                          </div>

                          <div className={styles.tags}>
                            {getDomainsDisplay(job).slice(0, 3).map((domain, idx) => (
                              <span key={idx} className={styles.tag}>{domain}</span>
                            ))}
                          </div>
                        </div>

                        <div className={styles.cardActions}>
                          <button
                            className={styles.viewBtn}
                            onClick={() => openModal(job)}
                          >
                            View Details
                          </button>
                          <button
                            className={styles.removeBtn}
                            onClick={(e) => handleUnsaveJob(job.id, e)}
                            disabled={unsavingJobId === job.id}
                          >
                            {unsavingJobId === job.id ? "Removing..." : "Remove"}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Pagination */}
                {totalPages > 1 && (
                  <div className={styles.pagination}>
                    {Array.from({ length: totalPages }).map((_, i) => {
                      const p = i + 1;
                      return (
                        <button
                          key={p}
                          className={`${styles.pageBtn} ${page === p ? styles.active : ""}`}
                          onClick={() => setPage(p)}
                        >
                          {p}
                        </button>
                      );
                    })}
                  </div>
              )}
            </>
          )}
          </div>
        </main>

        {/* Job Details Modal */}
        {isModalOpen && selectedJob && (
          <div className={styles.modalOverlay} onClick={closeModal}>
            <div className={styles.modalContent} onClick={(e) => e.stopPropagation()}>
              <button className={styles.closeBtn} onClick={closeModal}>×</button>

              <div className={styles.modalHeader}>
                <div className={styles.modalLogo}>
                  {selectedJob.organization?.logo ? (
                    <img src={selectedJob.organization.logo} alt={selectedJob.organization.name} />
                  ) : (
                    <span>{selectedJob.organization?.name?.[0] || "?"}</span>
                  )}
                </div>
                <div className={styles.modalJobInfo}>
                  <h2 className={styles.modalJobTitle}>{selectedJob.title}</h2>
                  <p className={styles.modalCompany}>{selectedJob.organization?.name}</p>
                  <div className={styles.modalMeta}>
                    <span>📍 {selectedJob.province}, {selectedJob.commune}</span>
                    <span>💼 {getWorkingModeDisplay(selectedJob)}</span>
                    <span>💰 {formatSalary(selectedJob)}</span>
                    <span>👥 {selectedJob.quantity} positions</span>
                  </div>
                </div>
                <div className={styles.modalActions}>
                  <button
                    className={styles.modalRemoveBtn}
                    onClick={(e) => handleUnsaveJob(selectedJob.id, e)}
                    disabled={unsavingJobId === selectedJob.id}
                  >
                    {unsavingJobId === selectedJob.id ? "Removing..." : "❤️ Remove"}
                  </button>
                </div>
              </div>

              <div className={styles.modalBody}>
                <div className={styles.section}>
                  <h3>Job Description</h3>
                  <p>{selectedJob.descriptions}</p>
                </div>

                {selectedJob.responsibility && (
                  <div className={styles.section}>
                    <h3>Responsibilities</h3>
                    <pre>{selectedJob.responsibility}</pre>
                  </div>
                )}

                {selectedJob.benefits && (
                  <div className={styles.section}>
                    <h3>Benefits</h3>
                    <pre>{selectedJob.benefits}</pre>
                  </div>
                )}

                {selectedJob.domains && selectedJob.domains.length > 0 && (
                  <div className={styles.section}>
                    <h3>Domains</h3>
                    <div className={styles.modalTags}>
                      {getDomainsDisplay(selectedJob).map((domain, idx) => (
                        <span key={idx} className={styles.modalTag}>{domain}</span>
                      ))}
                    </div>
                  </div>
                )}

                <div className={styles.section}>
                  <h3>Contact Information</h3>
                  <div className={styles.contactInfo}>
                    <div className={styles.contactItem}>
                      <span>📧 Email:</span>
                      <span>{selectedJob.contactEmail}</span>
                    </div>
                    <div className={styles.contactItem}>
                      <span>📞 Phone:</span>
                      <span>{selectedJob.contactPhone}</span>
                    </div>
                    <div className={styles.contactItem}>
                      <span>📍 Address:</span>
                      <span>{selectedJob.address}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </MainLayout>
  );
}
